/// Is this buffer full?\n  def full?(): Bool\n\n  /// Is this buffer empty?\n  def empty?(): Bool\n\n  /// Read an element from the tail of the buffer\n  def read(): Option[T]\n\n  /// Write an element to the head of the buffer\n  def write(el: T): Unit / Exception[BufferOverflow]\n}\n\ndef emptyBuffer[T](capacity: Int): Buffer[T] at global = {\n  if (capacity == 1) refBuffer()\n  else arrayBuffer(capacity)\n}\ndef arrayBuffer[T](initialCapacity: Int): Buffer[T] at global = {\n  // TODO allocate buffer (and array) into a region r.\n  val contents = array::unsafeAllocate[T](initialCapacity)\n  val head = ref(0)\n  val tail = ref(0)\n\n  def size(): Int =\n    if (tail.get >= head.get) { tail.get - head.get }\n    else { initialCapacity - head.get + tail.get }\n\n  def capacity(): Int = initialCapacity - size()\n\n  def buffer = new Buffer[T] {\n    def capacity() = capacity()\n    def full?() = capacity() <= 0\n    def empty?() = size() <= 0\n    def read() = {\n      if (size() <= 0) None()\n      else {\n        val result: T = contents.get(head.get)\n        head.set(mod(head.get + 1, initialCapacity))\n        Some(result)\n      }\n    }\n    def write(el: T) = {\n      if (capacity() <= 0) <> // raise(BufferOverflow())\n\n      contents.set(tail.get, el)\n      tail.set(mod(tail.get + 1, initialCapacity))\n    }\n  }\n  box buffer\n}\ndef refBuffer[T](): Buffer[T] at global = {\n  val content = ref(None())\n  box new Buffer[T] {\n    def capacity() = if (content.get.isEmpty) 1 else 0\n    def full?() = content.get.isDefined\n    def empty?() = isEmpty(content.get)\n    def read() = {\n      val res = content.get\n      content.set(None())\n      res\n    }\n    def write(el: T) = content.get match {\n      case Some(v) =>\n        <> // do raise(BufferOverflow(), "Cannot read element from buffer")\n      case None() =>\n        content.set(Some(el))\n    }\n  }\n}\n\nnamespace examples {\n  def main() = ignore[BufferOverflow] {\n    // Buffer with capacity 1\n    def b = emptyBuffer[Int](1)\n    println(b.capacity)\n    println(b.full?)\n\n    b.write(17)\n    println(b.read())\n\n    // buffer with capacity 3\n    def ringbuffer = emptyBuffer[Int](3)\n    ringbuffer.write(1)\n    ringbuffer.write(2)\n    println(ringbuffer.read())\n    ringbuffer.write(3)\n    println(ringbuffer.read())\n    println(ringbuffer.read())\n    ringbuffer.write(4)\n    ringbuffer.write(5)\n    println(ringbuffer.read())\n    println(ringbuffer.read())\n  }\n}\n'),tf("common/array.effekt",'module array\n\nimport effekt\nimport option\nimport stream\nimport control\nimport list\nimport exception\n\n/// A mutable 0-indexed fixed-sized array.\nextern type Array[T] =\n  js "Array"\n  chez "vector"\n  llvm "%Pos"\n\n/// We represent arrays like positive types.\n/// The tag is 0 and the obj points to memory with the following layout:\n///\n/// ```\n///    +--[ Header ]--+------+------------+\n///    | Rc  | Eraser | Size | Fields ... |\n///    +--------------+------+------------+\n/// ```\nextern llvm !!!MULTILINEMARKER!!!\ndefine void @array_erase_fields(ptr %array_pointer) {\nentry:\n    %data_pointer = getelementptr inbounds i64, ptr %array_pointer, i64 1\n    %size = load i64, ptr %array_pointer, align 8\n    %size_eq_0 = icmp eq i64 %size, 0\n    br i1 %size_eq_0, label %exit, label %loop\nloop:\n    %loop_phi = phi i64 [ %inc, %loop ], [ 0, %entry ]\n\n    %element_pointer = getelementptr inbounds %Pos, ptr %data_pointer, i64 %loop_phi\n    %element = load %Pos, ptr %element_pointer\n\n    call void @erasePositive(%Pos %element)\n    %inc = add nuw i64 %loop_phi, 1\n    %cmp = icmp ult i64 %inc, %size\n    br i1 %cmp, label %loop, label %exit\nexit:\n    ret void\n}\n!!!MULTILINEMARKER!!!\n\n/// Allocates a new array of size `size`, keeping its values _undefined_.\n/// Prefer using `array` constructor instead to ensure that values are defined.\nextern def unsafeAllocate[T](size: Int) at global: Array[T] =\n  js "(new Array(${size}))"\n  chez "(make-vector ${size})" // creates an array filled with 0s on CS\n  llvm !!!MULTILINEMARKER!!!\n    %size0 = shl i64 ${size}, 4\n    %size1 = add i64 %size0, 24\n    %calloc = tail call noalias ptr @calloc(i64 %size1, i64 1)\n    %eraser_pointer = getelementptr ptr, ptr %calloc, i64 1\n    %size_pointer = getelementptr ptr, ptr %calloc, i64 2\n    store i64 0, ptr %calloc\n    store ptr @array_erase_fields, ptr %eraser_pointer\n    store i64 ${size}, ptr %size_pointer\n    %ret_pos = insertvalue %Pos { i64 0, ptr poison }, ptr %calloc, 1\n    ret %Pos %ret_pos\n  !!!MULTILINEMARKER!!!\n\n/// Fills a given array in-place.\ndef fill[T](arr: Array[T], filler: T): Unit = {\n  arr.foreachIndex { (idx, _) =>\n    arr.set(idx, filler)\n  }\n}\n\n/// Creates a new Array of size `size` filled with the value `init`\ndef array[T](size: Int, init: T): Array[T] = {\n  val arr = unsafeAllocate[T](size);\n  arr.fill(init)\n  arr\n}\n\n/// Converts a List `list` to an Array\ndef fromList[T](list: List[T]): Array[T] = {\n  val listSize = list.size();\n  val arr = unsafeAllocate(listSize);\n\n  foreachIndex(list) { (i, head) =>\n    arr.set(i, head)\n  }\n  return arr;\n}\n\n/// Gets the length of the array in constant time.\nextern def size[T](arr: Array[T]) at {}: Int =\n  js "${arr}.length"\n  chez "(vector-length ${arr})"\n  llvm !!!MULTILINEMARKER!!!\n    %pos_data = extractvalue %Pos ${arr}, 1\n    %size_pointer = getelementptr inbounds i64, ptr %pos_data, i64 2\n    %size = load i64, ptr %size_pointer\n\n    tail call void @erasePositive(%Pos ${arr})\n    ret i64 %size\n  !!!MULTILINEMARKER!!!\n\nextern llvm !!!MULTILINEMARKER!!!\ndefine void @assertInbounds(i64 %index, %Pos %arr) alwaysinline {\n  %pos_data = extractvalue %Pos %arr, 1\n  %size_pointer = getelementptr inbounds i64, ptr %pos_data, i64 2\n  %size = load i64, ptr %size_pointer\n  %in_bounds = icmp ult i64 %index, %size\n  br i1 %in_bounds, label %ok, label %out\nout:\n  call void @exit(i64 1)\n  unreachable\nok:\n  ret void\n}\n!!!MULTILINEMARKER!!!\n\nextern js !!!MULTILINEMARKER!!!\n  function array$get(arr, index) {\n    if (index < 0 || index >= arr.length) throw \'Index out of bounds\';\n    return arr[index];\n  }\n!!!MULTILINEMARKER!!!\n\n\n/// Gets the element of the `arr` at given `index` in constant time.\n/// Aborts the program when the index is out of bounds.\nextern def get[T](arr: Array[T], index: Int) at global: T =\n  js "array$get(${arr}, ${index})"\n  chez "(vector-ref ${arr} ${index})"\n  llvm !!!MULTILINEMARKER!!!\n    call void @assertInbounds(i64 ${index}, %Pos ${arr})\n    %pos_data = extractvalue %Pos ${arr}, 1\n\n    %data_pointer = getelementptr inbounds ptr, ptr %pos_data, i64 3\n    %element_pointer = getelementptr inbounds %Pos, ptr %data_pointer, i64 ${index}\n    %element = load %Pos, ptr %element_pointer\n\n    tail call void @sharePositive(%Pos %element)\n    tail call void @erasePositive(%Pos ${arr})\n    ret %Pos %element\n  !!!MULTILINEMARKER!!!\n\nextern js !!!MULTILINEMARKER!!!\n  function array$set(arr, index, value) {\n    if (index < 0 || index >= arr.length) throw \'Index out of bounds\';\n    arr[index] = value;\n    return $effekt.unit\n  }\n!!!MULTILINEMARKER!!!\n\n/// Sets the element of the `arr` at given `index` to `value` in constant time.\n/// Aborts the program when the index is out of bounds.\nextern def set[T](arr: Array[T], index: Int, value: T) at global: Unit =\n  js "array$set(${arr}, ${index}, ${value})"\n  chez "(begin (vector-set! ${arr} ${index} ${value}) #f)"\n  llvm !!!MULTILINEMARKER!!!\n    call void @assertInbounds(i64 ${index}, %Pos ${arr})\n    %array_data = extractvalue %Pos ${arr}, 1\n\n    %data_pointer = getelementptr inbounds i64, ptr %array_data, i64 3\n    %element_pointer = getelementptr inbounds %Pos, ptr %data_pointer, i64 ${index}\n    %element = load %Pos, ptr %element_pointer, align 8\n    tail call void @erasePositive(%Pos %element)\n    store %Pos ${value}, ptr %element_pointer, align 8\n    tail call void @erasePositive(%Pos ${arr})\n    ret %Pos zeroinitializer\n  !!!MULTILINEMARKER!!!\n\n// Derived operations:\n\n/// Allocates a new array initialized with zero integer values.\nextern def allocateZeros(size: Int) at global: Array[Int] =\n  llvm { unsafeAllocate(size) }\n  vm { unsafeAllocate(size) }\n  default { array(size, 0) }\n\n/// Builds a new Array of size `size` from a computation `index` which gets an index\n/// and returns a value that will be on that position in the resulting array\ndef build[T](size: Int) { index: Int => T }: Array[T] = {\n  val arr = unsafeAllocate[T](size);\n  each(0, size) { i =>\n    set(arr, i, index(i))\n  };\n  arr\n}\n\n/// Resizes an array to a given size.\n///\n/// O(N + M)\ndef resize[T](source: Array[T], size: Int): Array[T] = {\n  val target = unsafeAllocate(size)\n  val n = min(source.size, target.size)\n  def go(i: Int): Array[T] =\n    if (i < n) {\n      target.set(i, source.get(i))\n      go(i + 1)\n    } else {\n      target\n    }\n  go(0)\n}\n\n/// Creates a copy of `arr`\ndef copy[T](array: Array[T]): Array[T] =\n  array.resize(array.size)\n\n/// Copies `length`-many elements from `from` to `to`\n/// starting at `start` (in `from`) and `offset` (in `to`)\n/// Panics if any of those are out of bounds.\ndef copy[T](from: Array[T], start: Int, to: Array[T], offset: Int, length: Int): Unit = {\n  def go(i: Int, j: Int, n: Int): Unit =\n    if (n > 0) {\n      to.set(j, from.get(i))\n      go(i + 1, j + 1, n - 1)\n    }\n  go(start, offset, length)\n}\n\n\n// Utility functions:\n\n/// Swap the value at index i with that at index j.\n/// Panics if the indices are out bounds.\n///\n/// O(1)\ndef swap[A](arr: Array[A], i: Int, j: Int): Unit = {\n  val tmp = arr.get(i)\n  arr.set(i, arr.get(j))\n  arr.set(j, tmp)\n}\n\n/// Converts the given array into a list.\n///\n/// O(N)\ndef toList[T](arr: Array[T]): List[T] = {\n  var i = arr.size - 1;\n  var l = Nil[T]()\n  while (i >= 0) {\n    l = Cons(arr.get(i), l)\n    i = i - 1\n  }\n  l\n}\n\n/// Traverse an array, applying the given action on every element.\n///\n/// O(N)\ndef foreach[T](arr: Array[T]){ action: T => Unit }: Unit =\n  each(0, arr.size) { i =>\n    action(arr.get(i))\n  }\n\n/// Traverse an array, applying the given action on every element.\n///\n/// O(N)\ndef foreach[T](arr: Array[T]){ action: (T) {Label} => Unit }: Unit =\n  each(0, arr.size) { (i) {label} =>\n    action(arr.get(i)) {label}\n  }\n\n/// Traverse an array, applying the given action on every element and its (zero-based) index.\n///\n/// O(N)\ndef foreachIndex[T](arr: Array[T]){ action: (Int, T) => Unit }: Unit =\n  each(0, arr.size) { i =>\n    action(i, arr.get(i))\n  }\n\n/// Traverse an array, applying the given action on every element and its (zero-based) index.\n///\n/// O(N)\ndef foreachIndex[T](arr: Array[T]){ action: (Int, T) {Label} => Unit }: Unit =\n  each(0, arr.size) { (i) {label} =>\n    action(i, arr.get(i)) {label}\n  }\n\n/// Sum the elements of the array.\n///\n/// O(N)\ndef sum(arr: Array[Int]): Int = {\n  var acc = 0\n  arr.foreach { x =>\n    acc = acc + x\n  }\n  acc\n}\n\n/// Checks whether two given arrays are equal with respect to an equalty funciton defined on their element.\n///\n/// O(N)\ndef equals[A](this: Array[A], other: Array[A]) { eq: (A, A) => Bool }: Bool = {\n  if (this.size != other.size) false\n  else {\n    var res = true\n    this.foreachIndex { (idx, elem) {label} =>\n      if (not(eq(elem, other.get(idx)))) {\n        res = false\n        label.break()\n      }\n    }\n    res\n  }\n}\n\n/// Map a function `f` over the elements in a given array.\n/// Modifies the array in-place.\n///\n/// O(N)\ndef map[A](arr: Array[A]) { f: A => A }: Unit = {\n  arr.foreachIndex { (idx, elem) =>\n    arr.set(idx, f(arr.get(idx)))\n  }\n}\n\n/// Map a function over elements.\n/// Allocates a new array of the same size.\n///\n/// O(N)\ndef mapped[A, B](arr: Array[A]) { f: A => B }: Array[B] = {\n  val res = unsafeAllocate(arr.size)\n  arr.foreachIndex { (idx, elem) =>\n    res.set(idx, f(arr.get(idx)))\n  }\n  res\n}\n\n/// Reverses an array in-place.\n///\n/// O(N)\ndef reverse[A](arr: Array[A]): Unit = {\n  val size = arr.size()\n  val mid = size / 2\n\n  // Swap elements from start and end, moving towards the middle\n  each(0, mid) { i =>\n    val temp = arr.get(i)\n    val j = size - 1 - i\n    val other = arr.get(j)\n    arr.set(i, other)\n    arr.set(j, temp)\n  }\n}\n/// Creates a new array with elements in reverse order.\n///\n/// O(N)\ndef reversed[A](arr: Array[A]): Array[A] = {\n  val size = arr.size()\n  val result = unsafeAllocate[A](size)\n\n  // Copy elements in reverse order to new array\n  each(0, size) { i =>\n    val value = arr.get(i)\n    result.set(size - 1 - i, value)\n  }\n  result\n}\n\n/// Fold an array using `f`, starting from the left given a starting value.\n///\n/// O(N)\ndef foldLeft[A, B](arr: Array[A], init: B) { f: (B, A) => B }: B = {\n  var acc = init;\n  arr.foreach { x => acc = f(acc, x) };\n  acc\n}\n\n/// Fold an array using `f`, starting from the right given a starting value.\n///\n/// O(N)\ndef foldRight[A, B](arr: Array[A], init: B) { f: (A, B) => B }: B = {\n  var acc = init;\n  arr.reversed.foreach { x => acc = f(x, acc) };\n  acc\n}\n\n/// Filters a given array with respect to a given predicate such that a\n/// new array containing all the elements for which the predicate\n/// holds is allocated.\n///\n/// O(N)\ndef filtered[A](arr: Array[A]) { shouldKeep: A => Bool }: Array[A] = {\n  val res = arr.copy()\n  var idx = 0\n  arr.foreach { x =>\n    if (shouldKeep(x)) {\n      res.set(idx, x)\n      idx = idx + 1\n    }\n  }\n  res.resize(idx)\n}\n\n/// Check if predicate is true for all elements.\n///\n/// O(N)\ndef all[A](arr: Array[A]) { predicate: A => Bool }: Bool = {\n  var result = true\n  arr.foreach { (x) {label} =>\n    if (not(predicate(x))) {\n      result = false\n      label.break()\n    }\n  }\n  result\n}\n\n/// Check if predicate is true for at least one element.\n///\n/// O(N)\ndef any[A](arr: Array[A]) { predicate: A => Bool }: Bool = {\n  not(arr.all { x => not(predicate(x)) })\n}\n\n/// Count elements satisfying the predicate.\n///\n/// O(N)\ndef count[A](arr: Array[A]) { predicate: A => Bool }: Int = {\n  var count = 0\n  arr.foreach { x =>\n    if (predicate(x)) count = count + 1\n  }\n  count\n}\n\n/// Take first n elements.\n/// Returns a new array.\n///\n/// O(N)\ndef take[A](arr: Array[A], n: Int): Array[A] = {\n  val len = min(max(0, n), arr.size)\n  val result = unsafeAllocate[A](len)\n  each(0, len) { i =>\n    result.set(i, arr.get(i))\n  }\n  result\n}\n\n/// Drop first n elements.\n/// Returns a new array.\n///\n/// O(N)\ndef drop[A](arr: Array[A], n: Int): Array[A] = {\n  val start = min(max(0, n), arr.size)\n  val len = arr.size - start\n  val result = unsafeAllocate[A](len)\n  each(0, len) { i =>\n    result.set(i, arr.get(i + start))\n  }\n  result\n}\n\n/// Return a slice from start (inclusive) to end (exclusive).\n/// Returns a new array.\n///\n/// O(N)\ndef sliced[A](arr: Array[A], start: Int, end: Int): Array[A] = {\n  val validStart = min(max(0, start), arr.size)\n  val validEnd = min(max(validStart, end), arr.size)\n  val len = validEnd - validStart\n  val result = unsafeAllocate[A](len)\n  each(0, len) { i =>\n    result.set(i, arr.get(i + validStart))\n  }\n  result\n}\n\n/// Zip two arrays into an array of pairs.\n/// Length is minimum of input lengths.\n///\n/// O(min(N, M))\ndef zipped[A, B](this: Array[A], other: Array[B]): Array[(A, B)] = {\n  val len = min(this.size, other.size)\n  val result = unsafeAllocate[(A, B)](len)\n  each(0, len) { i =>\n    result.set(i, (this.get(i), other.get(i)))\n  }\n  result\n}\n\n/// Combine two arrays using given function.\n/// Length is minimum of input lengths.\n///\n/// O(min(N, M))\ndef zippedWith[A, B, C](this: Array[A], other: Array[B]) { f: (A, B) => C }: Array[C] = {\n  val len = min(this.size, other.size)\n  val result = unsafeAllocate[C](len)\n  each(0, len) { i =>\n    result.set(i, f(this.get(i), other.get(i)))\n  }\n  result\n}\n\n/// Produce a pair of arrays from an array of pairs.\n/// Allocates two new arrays as a result.\n///\n/// O(N)\ndef unzipped[A, B](arr: Array[(A, B)]): (Array[A], Array[B]) = {\n  val arr1 = unsafeAllocate(arr.size)\n  val arr2 = unsafeAllocate(arr.size)\n  arr.foreachIndex { (idx, tpl) =>\n    val (x, y) = tpl\n    arr1.set(idx, x)\n    arr2.set(idx, y)\n  }\n  (arr1, arr2)\n}\n\n/// Partition a given array into two arrays.\n/// The left array contains the elements that satsify the predicate,\n/// the right array contains the elements that do not.\n///\n/// O(N)\ndef partioned[A](arr: Array[A]) { pred: A => Bool }: (Array[A], Array[A]) = {\n  val tcases = arr.copy()\n  val fcases = arr.copy()\n  var tidx = 0\n  var fidx = 0\n  arr.foreach { x =>\n    if (pred(x)) {\n      tcases.set(tidx, x)\n      tidx = tidx + 1\n    } else {\n      fcases.set(fidx, x)\n      fidx = fidx + 1\n    }\n  }\n  (tcases.resize(tidx), fcases.resize(fidx))\n}\n\n/// Get the _first_ index of the last occurance of `elem`, if there is any.\n///\n/// O(N)\ndef indexOf[A](arr: Array[A], toFind: A) { eq: (A, A) => Bool }: Option[Int] = {\n  var found = None[Int]()\n  arr.foreachIndex { (idx, elem) {label} =>\n    if (eq(elem, toFind) && found.isEmpty) {\n      found = Some(idx)\n      label.break()\n    }\n  }\n  found\n}\n\n/// Get the _last_ index of the last occurance of `elem`, if there is any.\n///\n/// O(N)\ndef lastIndexOf[A](arr: Array[A], toFind: A) { eq: (A, A) => Bool }: Option[Int] = {\n  var lastFound = None[Int]()\n  arr.foreachIndex { (idx, elem) =>\n    if (eq(elem, toFind)) {\n      lastFound = Some(idx)\n    }\n  }\n  lastFound\n}\n\n/// Perform binary search to find the index of a given element.\n///\n/// O(log N)\ndef binarySearch[A](arr: Array[A], toFind: A) { ord: (A, A) => Ordering }: Option[Int] = {\n  def binarySearch(lowerIdx: Int, upperIdx: Int): Option[Int] = {\n    if (lowerIdx > upperIdx) None()\n    else {\n      val mid = lowerIdx + (upperIdx - lowerIdx) / 2\n      val current = arr.get(mid)\n      ord(current, toFind) match {\n        case Less() => binarySearch(mid + 1, upperIdx)\n        case Greater() => binarySearch(lowerIdx, mid - 1)\n        case Equal() => Some(mid)\n      }\n    }\n  }\n  binarySearch(0, arr.size - 1)\n}\n\n/// Sort an array in-place using provided comparison function.\n/// Note: `sort` is unstable since it uses QuickSort (unlike `list::sortBy`)\n///\n/// O(N log N) average case\ndef sort[A](arr: Array[A]) { ord: (A, A) => Ordering }: Unit = {\n  def partition(low: Int, high: Int): Int = {\n    val pivot = arr.get(high)\n    var i = low - 1\n\n    each(low, high) { j =>\n      if (ord(arr.get(j), pivot) is Less()) {\n        i = i + 1\n        swap(arr, i, j)\n      }\n    }\n    swap(arr, i + 1, high)\n    i + 1\n  }\n\n  def quickSort(low: Int, high: Int): Unit = {\n    if (low < high) {\n      val par = partition(low, high)\n      quickSort(low, par - 1)\n      quickSort(par + 1, high)\n    }\n  }\n\n  quickSort(0, arr.size - 1)\n}\n\n/// Sort an array using provided comparison function.\n/// A newly allocated sorted array is returned as result, i.e., the sorting is not in-place.\n/// Note: `sorted` is unstable since it uses QuickSort (unlike `list::sortBy`)\n///\n/// O(N log N) average case\ndef sorted[A](arr: Array[A]) { ord: (A, A) => Ordering }: Array[A] = {\n  val res = arr.copy()\n  res.sort { ord }\n  res\n}\n\n// Show Instances\n// --------------\n\n// TODO: These can eventually be replaced if we ever figure out monomorphization on extern types\n\ndef showBuiltin[A](arr: Array[A]) { showA: A => String }: String = {\n  var output = "Array("\n  val lastIndex = arr.size - 1\n\n  arr.foreachIndex { (index, a) =>\n    if (index == lastIndex) output = output ++ showA(a)\n    else output = output ++ showA(a) ++ ", "\n  }\n  output = output ++ ")"\n\n  output\n}\n\ndef showBuiltin(l: Array[Int]): String = showBuiltin(l) { e => show(e) }\ndef showBuiltin(l: Array[Double]): String = showBuiltin(l) { e => show(e) }\ndef showBuiltin(l: Array[Bool]): String = showBuiltin(l) { e => show(e) }\ndef showBuiltin(l: Array[String]): String = showBuiltin(l) { e => e }\n\ndef println(l: Array[Int]): Unit = println(showBuiltin(l))\ndef println(l: Array[Double]): Unit = println(showBuiltin(l))\ndef println(l: Array[Bool]): Unit = println(showBuiltin(l))\ndef println(l: Array[String]): Unit = println(showBuiltin(l))\n\n// Streaming\n// ---------\n\n/// Turns an `array` into a producer of a push stream\n/// by emitting each contained value from 0 to length - 1.\ndef each[T](array: Array[T]): Unit / emit[T] = {\n  val n = array.size\n  def go(i: Int): Unit = {\n    if (i < n) {\n      do emit(array.get(i))\n      go(i + 1)\n    }\n  }\n  go(0)\n}\n\n/// Connects `array` as a producer to a given pull stream `driver` acting as a consumer.\ndef feed[T, R](array: Array[T]) { driver: () => R / next[T] }: R = {\n  var i = 0\n  try {\n    driver()\n  } with next[T] {\n    resume {\n      if (i < array.size) {\n        val c = i\n        i = c + 1\n        array.get(c)\n      } else {\n        do stop()\n      }\n    }\n  }\n}\n\n/// Collects elements emitted by a push stream producer `stream` into a new array,\n/// discarding the result of the producer.\n/// The provided capacity is a hint for the expected number of elements.\n/// It must be strictly larger than zero.\ndef collect[A](capacity: Int) { stream: () => Unit / emit[A] }: Array[A] =\n  returning::collect[A, Unit](capacity){stream}.second\n\n/// Collects elements emitted by a push stream producer `stream` into a new array,\n/// discarding the result of the producer.\ndef collect[A] { stream: () => Unit / emit[A] }: Array[A] =\n  collect[A](4){stream}\n\nnamespace returning {\n\n  /// Collects elements emitted by a push stream producer `stream` into a new array,\n  /// returning the result of the producer as well as the collected array.\n  /// The provided capacity is a hint for the expected number of elements.\n  /// It must be strictly larger than zero.\n  def collect[A, R](capacity: Int) { stream: () => R / emit[A] }: (R, Array[A]) = {\n    var i = 0\n    var a = unsafeAllocate(capacity)\n    try {\n      (stream(), a.resize(i))\n    } with emit[A] { (v) =>\n      if (i >= a.size) { a = a.resize(2 * a.size) }\n      a.set(i, v)\n      i = i + 1\n      resume(())\n    }\n  }\n\n  /// Collects elements emitted by a push stream producer `stream` into a new array,\n  /// returning the result of the producer as well as the collected array.\n  def collect[A, R] { stream: () => R / emit[A] }: (R, Array[A]) =\n    returning::collect[A, R](4){stream}\n\n}\n'),tf("common/bytestream.effekt","import option\nimport stringbuffer\nimport stream\nimport char\nimport io/error\nimport bytearray\n\n// assumes by default:\n// BE byteorder, BE bitorder, unsigned\n\n// Wrappers\n// --------\n/// A with explicit big-endian order\nrecord BE[A](raw: A)\n/// A with explicit little-endian order\nrecord LE[A](raw: A)\n/// A with explicit width in current unit\n/// (bits for bitstreams, bytes for bytestreams)\nrecord OfWidth[A](raw: A, width: Int)\n/// explicitly signed A\nrecord Signed[A](raw: A)\n\n/// Bits\ntype Bit { B0(); B1() }\n\n/// not on Bits\ndef not(b: Bit): Bit = b match {\n  case B0() => B1()\n  case B1() => B0()\n}\n\n/// Splices allowed in hex/byte stream literals\neffect HexSplices = {\n  splice[Char], splice[String], \n  splice[Unit], \n  splice[Int],\n  splice[Byte],\n  splice[BE[Int]], splice[LE[Int]],\n  splice[LE[Signed[Int]]], splice[OfWidth[LE[Int]]], splice[OfWidth[LE[Signed[Int]]]],\n  splice[BE[Signed[Int]]], splice[OfWidth[BE[Int]]], splice[OfWidth[BE[Signed[Int]]]],\n  splice[ByteArray]\n}\n\n// Splitting\n// ---------\n\n/// emit bytes of the given int as a w bytes in little-endian byte order\ndef bytesLE(int: Int, w: Int): Unit / emit[Byte] = {\n  var c = int\n  repeat(w){\n    do emit(mod(c, 256).toByte)\n    c = c / 256\n  }\n}\n\n/// emit bytes of the given int as a 4 bytes in little-endian byte order\ndef bytesLE(int: Int): Unit / emit[Byte] = bytesLE(int, 4)\n\n/// emit bytes of the given int as a w bytes in big-endian byte order\ndef bytesBE(n: Int, width: Int): Unit / emit[Byte] = {\n  var shift = bitwiseShl(width - 1, 3)\n  repeat(width) {\n    do emit(bitwiseAnd(bitwiseShr(n, shift), 255).toByte)\n    shift = shift - 8\n  }\n}\n\n/// emit bytes of the given int as a 4 bytes in big-endian byte order\ndef bytesBE(n: Int): Unit / emit[Byte] = bytesBE(n, 4)\n\n/// emit bytes of the given int as width bytes (in 2s-complement) in little-endian byte order\ndef signedBytesLE(int: Int, width: Int): Unit / emit[Byte] =\n  if (int < 0) {\n    bytesLE(bitwiseNot(neg(int)) + 1, width)\n  } else {\n    bytesLE(int, width)\n  }\n/// emit bytes of the given int as width bytes (in 2s-complement) in big-endian byte order\ndef signedBytesBE(int: Int, width: Int): Unit / emit[Byte] = {\n  if (int < 0) {\n    bytesBE(bitwiseNot(neg(int)) + 1, width)\n  } else {\n    bytesBE(int, width)\n  }\n}\n\n/// emit bytes of the given int as 4 bytes (in 2s-complement) in little-endian byte order\ndef signedBytesLE(int: Int): Unit / emit[Byte] = signedBytesLE(int, 4)\n\n/// emit bytes of the given int as 4 bytes (in 2s-complement) in big-endian byte order\ndef signedBytesBE(int: Int): Unit / emit[Byte] = signedBytesBE(int, 4)\n\n\n\n// Splicers\n// --------\n\n/// Splicer to emit the bytes in hex notation given, plus eventual splices\n/// Ignores whitespace\ndef hex{ body: => Unit / { write, HexSplices } }: Unit / emit[Byte] = {\n  try {\n    try {\n      body()\n    }\n    with splice[String] { s =>\n      feed(s){ loop { do splice[Char](do next[Char]()) } }\n      resume(())\n    }\n    with splice[ByteArray] { ba =>\n      ba.foreach{ b => do splice[Byte](b) }\n      resume(())\n    }\n  }\n  with write { s =>\n      feed(s){\n        loop {\n          attempt {\n            val upper: Int = hexDigitValue(do next[Char]())\n            val lower: Int = hexDigitValue(do next[Char]())\n            do emit[Byte]((16 * upper + lower).toByte)\n          } { () }\n        }\n      }\n      resume(())\n    }\n  with splice[Char] { c => do emit[Byte](c.toInt.toByte); resume(()) }\n  with splice[Byte] { b => do emit(b); resume(()) }\n  with splice[Unit] { u => resume(()) }\n  with splice[Int] { n => bytesBE(n); resume(()) }\n  with splice[LE[Int]] { w => bytesLE(w.raw); resume(()) }\n  with splice[BE[Int]] { v => bytesBE(v.raw); resume(()) }\n  with splice[LE[Signed[Int]]] { w => signedBytesLE(w.raw.raw); resume(()) }\n  with splice[OfWidth[LE[Int]]] { w => bytesLE(w.raw.raw, w.width); resume(()) }\n  with splice[OfWidth[LE[Signed[Int]]]] { w => signedBytesLE(w.raw.raw.raw, w.width); resume(()) }\n  with splice[BE[Signed[Int]]] { w => signedBytesBE(w.raw.raw); resume(()) }\n  with splice[OfWidth[BE[Int]]] { w => bytesBE(w.raw.raw, w.width); resume(()) }\n  with splice[OfWidth[BE[Signed[Int]]]] { w => signedBytesBE(w.raw.raw.raw, w.width); resume(()) }\n}\n\n/// convert the given hex notation to an integer (big-endian)\ndef x{ body: => Unit / { write, HexSplices } }: Int = {\n  var res = 0\n  for[Byte]{ hex{body} }{ v => res = res * 256 + v.toInt }\n  res\n}\n\n\n// Sub-Byte\n// ========\n\n// From/to Bytes\n// -------------\n/// emit bits of the given Byte as 8 Bits in little-endian bit order\ndef bitsLE(byte: Byte): Unit / emit[Bit] = {\n  val v = byte.toInt\n  var mask = 1\n  repeat(8){\n    bitwiseAnd(v, mask) match {\n      case 0 => do emit(B0())  \n      case _ => do emit(B1())\n    }\n    mask = mask * 2\n  }\n}\n\n/// emit bits of the given Byte as 8 Bits in big-endian bit order\ndef bitsBE(byte: Byte): Unit / emit[Bit] = {\n  val v = byte.toInt\n  var mask = 128\n  repeat(8){\n    bitwiseAnd(v, mask) match {\n      case 0 => do emit(B0())  \n      case _ => do emit(B1())\n    }\n    mask = mask / 2\n  }\n}\n\n/// emit bits of the given Byte as width Bits in little-endian bit order\ndef bitsLE(v: Int, width: Int): Unit / emit[Bit] = {\n  var mask = 1\n  repeat(width){\n    bitwiseAnd(v, mask) match {\n      case 0 => do emit(B0())  \n      case _ => do emit(B1())\n    }\n    mask = mask * 2\n  }\n}\n\n/// emit bits of the given int as width Bits in big-endian bit order\ndef bitsBE(v: Int, width: Int): Unit / emit[Bit] = {\n  var mask = bitwiseShl(1, width - 1)\n  repeat(width){\n    bitwiseAnd(v, mask) match {\n      case 0 => do emit(B0())  \n      case _ => do emit(B1())\n    }\n    mask = mask / 2\n  }\n}\n\n/// emit bits of the given int as 32 Bits in big-endian bit order\ndef bitsBE(int: Int): Unit / emit[Bit] = bitsBE(int, 32)\n\n/// collect bits in big-endian bit order into an Int\ndef collectBitsBE{ body: => Unit / emit[Bit] }: Int = {\n  var res = 0\n  try body() with emit[Bit] { b =>\n    res = b match {\n      case B0() => res * 2\n      case B1() => res * 2 + 1\n    }\n    resume(())\n  }\n  res\n}\n\n/// split emitted bytes and emit the individual bits in big-endian bit order\ndef ungroupBytesBE{ body: => Unit / emit[Byte] }: Unit / emit[Bit] =\n  for[Byte]{body}{ b => bitsBE(b) }\n\n/// streaming negation in 2s-complement for little-endian bitstreams\ndef twoscomplementLE{ body: => Unit / emit[Bit] }: Unit / emit[Bit] = {\n  var carry = true\n  try body()\n  with emit[Bit] {\n    case B0() => if(carry) { do emit(B0()) } else { do emit(B1()) }; resume(())\n    case B1() => if(carry) { do emit(B1()); carry = false } else { do emit(B0()) }; resume(())\n  }\n}  \n\n/// group 8 bits into a byte each, big-endian bit order.\n/// NOTE: The remainder is dropped.\ndef groupBytesBE{ body: => Unit / emit[Bit] }: Unit / emit[Byte] = {\n  var next = 0\n  var p = 128\n  for[Bit]{body}{ b =>\n    b match {\n      case B0() => ()\n      case B1() => next = next + p\n    }\n    p = p / 2\n    if(p == 0) {\n      do emit(next.toByte)\n      next = 0\n      p = 128\n    }\n  }\n}\n\n/// group 8 bits into a byte each, little-endian bit order.\n/// NOTE: The remainder is dropped.\ndef groupBytesLE{ body: => Unit / emit[Bit] }: Unit / emit[Byte] = {\n  var next = 0\n  var p = 1\n  for[Bit]{body}{ b =>\n    b match {\n      case B0() => ()\n      case B1() => next = next + p\n    }\n    p = p * 2\n    if(p == 256) {\n      do emit(next.toByte)\n      next = 0\n      p = 1\n    }\n  }\n}\n\n// Literals/splices\n// ----------------\n/// Splices allowed in bit stream literals\neffect BitSplices = {\n  splice[Unit], splice[Bit],\n  splice[Byte],\n  splice[LE[Int]], splice[BE[Int]],\n  splice[LE[Signed[Int]]], splice[BE[Signed[Int]]],\n  splice[OfWidth[LE[Int]]], splice[OfWidth[BE[Int]]],\n  splice[OfWidth[LE[Signed[Int]]]], splice[OfWidth[BE[Signed[Int]]]]\n}\n/// Splicer to emit the bits in binary notation given, plus evenutal splices\n/// Ignores whitespace\ndef bit{ body: => Unit / { write, BitSplices } }: Unit / emit[Bit] = {\n  try {\n    ungroupBytesBE{\n      try {\n        body()\n      }\n      with splice[LE[Int]] { i => bytesLE(i.raw); resume(()) }\n      with splice[BE[Int]] { i => bytesBE(i.raw); resume(()) }\n      with splice[LE[Signed[Int]]] { i => signedBytesLE(i.raw.raw); resume(()) }\n      with splice[BE[Signed[Int]]] { i => signedBytesBE(i.raw.raw); resume(()) }\n    }\n  }\n  with write { s =>\n    feed(s){\n      loop {\n        do next[Char]() match {\n          case '0' => do emit(B0())\n          case '1' => do emit(B1())\n          case _ => ()\n        }\n      }\n    }\n    resume(())\n  }\n  with splice[Unit] { _ => resume(()) }\n  with splice[Bit] { b => do emit(b); resume(()) }\n  with splice[Byte] { b => bitsBE(b); resume(()) }\n  with splice[OfWidth[LE[Int]]] { i =>\n    bitsLE(i.raw.raw, i.width)\n    resume(())\n  }\n  with splice[OfWidth[LE[Signed[Int]]]] { i =>\n    if(i.raw.raw.raw < 0){\n      twoscomplementLE{ bitsLE(0 - i.raw.raw.raw, i.width) }\n    } else {\n      bitsLE(i.raw.raw.raw,