n/// A file descriptor. Should not be inspected.\ntype File = Int\n\n\n/// Reads a file at given path as utf8 encoded string.\ndef readFile(path: String): String / Exception[IOError] = {\n  val file = openForReading(path);\n  with on[IOError].finalize { close(file) }\n\n  val chunkSize = 1048576 // 1MB\n  var buffer = bytearray::allocate(chunkSize)\n  var offset = 0\n\n  def go(): String = {\n    read(file, buffer, offset, chunkSize, -1) match {\n      case 0 =>\n        buffer.resize(offset).toString\n      case n =>\n        offset = offset + n\n        if (offset + chunkSize > buffer.size) {\n          buffer = buffer.resize(2 * buffer.size)\n        }\n        go()\n    }\n  }\n\n  go()\n}\n\n/// Writes the (utf8 encoded) string `contents` into the specified file.\ndef writeFile(path: String, contents: String): Unit / Exception[IOError] = {\n  val file = openForWriting(path);\n  with on[IOError].finalize { close(file) }\n\n  val chunkSize = 1048576 // 1MB\n  val buffer = contents.fromString\n  var offset = 0;\n\n  def go(): Unit = {\n    val n = write(file, buffer, offset, min(buffer.size - offset, chunkSize), -1)\n    offset = offset + n\n    if (offset < buffer.size) { go() }\n  }\n\n  go()\n}\n\n/// Appends the (utf8 encoded) string `contents` to the specified file.\ndef appendFile(path: String, contents: String): Unit / Exception[IOError] = {\n  val file = openForAppending(path);\n  with on[IOError].finalize { close(file) }\n\n  val chunkSize = 1048576 // 1MB\n  val buffer = contents.fromString\n  var offset = 0;\n\n  def go(): Unit = {\n    val n = write(file, buffer, offset, min(buffer.size - offset, chunkSize), -1)\n    offset = offset + n\n    if (offset < buffer.size) { go() }\n  }\n\n  go()\n}\n\ndef writeFileUTF8[R](path: String) { stream: () => R / emit[Char] }: R / Exception[IOError] =\n  writeFile(path) { encodeUTF8 { stream() } }\n\ndef readFileUTF8[R](path: String) { driver: () => R / next[Char] }: R / Exception[IOError] =\n  readFile(path) { decodeUTF8 { driver() } }\n\ndef writeFile[R](path: String) { stream: () => R / emit[Byte] }: R / Exception[IOError] = {\n\n  val file = openForWriting(path);\n  with on[IOError].finalize { close(file) }\n\n  val chunkSize = 1048576 // 1MB\n  val buffer = bytearray::allocate(chunkSize)\n  var offset = 0\n\n  def push(i: Int, n: Int): Unit = {\n    val r = write(file, buffer, i, n, -1)\n    if (r < n) {\n      push(i + r, n - r)\n    }\n  }\n\n  try {\n    val r = stream()\n    push(0, offset)\n    return r\n  } with emit[Byte] { (byte) =>\n    if (offset >= buffer.size) {\n      push(0, buffer.size)\n      offset = 0\n    }\n    buffer.set(offset, byte)\n    offset = offset + 1\n    resume(())\n  }\n}\n\ndef readFile[R](path: String) { driver: () => R / next[Byte] }: R / Exception[IOError] = {\n\n  val file = openForReading(path);\n  with on[IOError].finalize { close(file) }\n\n  val chunkSize = 1048576 // 1MB\n  val buffer = bytearray::allocate(chunkSize)\n  var offset = 0\n  var length = 0\n\n  def pull(): Unit / stop = {\n    read(file, buffer, 0, chunkSize, -1) match {\n      case 0 =>\n        do stop()\n      case n =>\n        length = n\n    }\n  }\n\n  try {\n    driver()\n  } with next[Byte] {\n    resume {\n      if (offset >= length) {\n        pull()\n        offset = 0\n      }\n      val byte = buffer.get(offset)\n      offset = offset + 1\n      return byte\n    }\n  }\n}\n\n/// An abstract interface applications can program against.\n///\n/// Can be interpreted with the `filesystem` handler, or virtualized etc.\n///\n/// See example below.\ninterface Files {\n  def readFile(path: String): String\n  def writeFile(path: String, contents: String): Unit\n}\n\n/// Using the file system via node.js\ndef filesystem[R] { program: => R / Files }: R / Exception[IOError] = // TODO move Exception to be bidirectional\n  try { program() }\n  with Files {\n    def readFile(path) = resume(readFile(path))\n    def writeFile(path, contents) = resume(writeFile(path, contents))\n  }\n\n\ndef openForReading(path: String): File / Exception[IOError] =\n  internal::checkResult(internal::openForReading(path))\n\ndef openForWriting(path: String): File / Exception[IOError] =\n  internal::checkResult(internal::openForWriting(path))\n\ndef openForAppending(path: String): File / Exception[IOError] =\n  internal::checkResult(internal::openForAppending(path))\n\ndef read(file: File, buffer: ByteArray, offset: Int, size: Int, position: Int): Int / Exception[IOError] =\n  internal::checkResult(internal::read(file, buffer, offset, size, position))\n\ndef write(file: File, buffer: ByteArray, offset: Int, size: Int, position: Int): Int / Exception[IOError] =\n  internal::checkResult(internal::write(file, buffer, offset, size, position))\n\ndef close(file: File): Unit / Exception[IOError] = {\n  internal::checkResult(internal::close(file)); ()\n}\n\ndef mkdir(path: String): Unit / Exception[IOError] = {\n  internal::checkResult(internal::mkdir(path)); ()\n}\n\nnamespace internal {\n\n  extern js !!!MULTILINEMARKER!!!\n    /**\n     * Nodejs file operations expect buffers, but we represent buffers as typed arrays.\n     * This function converts between the two without copying.\n     */\n    function toBuffer(buffer) {\n      return Buffer.from(buffer.buffer, buffer.byteOffset, buffer.byteLength)\n    }\n  !!!MULTILINEMARKER!!!\n\n  extern jsNode !!!MULTILINEMARKER!!!\n    const fs = require("fs");\n\n    function open(path, flags, callback) {\n      fs.open(path, flags, (err, file) => {\n        if (err) { callback(err.errno) } else { callback(file) }\n      })\n    }\n\n    function read(file, buffer, offset, size, position, callback) {\n      let positionOrNull = position === -1 ? null : position;\n      fs.read(file, toBuffer(buffer), offset, size, positionOrNull, (err, bytesRead) => {\n        if (err) { callback(err.errno) } else { callback(bytesRead) }\n      })\n    }\n\n    function write(file, buffer, offset, size, position, callback) {\n      let positionOrNull = position === -1 ? null : position;\n      fs.write(file, toBuffer(buffer), offset, size, positionOrNull, (err, bytesWritten) => {\n        if (err) { callback(err.errno) } else { callback(bytesWritten) }\n      })\n    }\n\n    function close(file, callback) {\n      fs.close(file, (err) => {\n        if (err) { callback(err.errno) } else { callback(0) }\n      })\n    }\n\n    function mkdir(path, callback) {\n      fs.mkdir(path, (err) => {\n        if (err) { callback(err.errno) } else { callback(0) }\n      })\n    }\n  !!!MULTILINEMARKER!!!\n\n  extern llvm !!!MULTILINEMARKER!!!\n    declare void @c_fs_open_reading(%Pos, %Stack)\n    declare void @c_fs_open_writing(%Pos, %Stack)\n    declare void @c_fs_open_appending(%Pos, %Stack)\n    declare void @c_fs_read(%Int, %Pos, %Int, %Int, %Int, %Stack)\n    declare void @c_fs_write(%Int, %Pos, %Int, %Int, %Int, %Stack)\n    declare void @c_fs_close(%Int, %Stack)\n    declare void @c_fs_mkdir(%Pos, %Stack)\n  !!!MULTILINEMARKER!!!\n\n  extern def openForReading(path: String) at async: Int =\n    jsNode "$effekt.capture(callback => open(${path}, \'r\', callback))"\n    llvm !!!MULTILINEMARKER!!!\n      call void @c_fs_open_reading(%Pos ${path}, %Stack %stack)\n      ret void\n    !!!MULTILINEMARKER!!!\n\n  extern def openForWriting(path: String) at async: Int =\n    jsNode "$effekt.capture(callback => open(${path}, \'w\', callback))"\n    llvm !!!MULTILINEMARKER!!!\n      call void @c_fs_open_writing(%Pos ${path}, %Stack %stack)\n      ret void\n    !!!MULTILINEMARKER!!!\n\n  extern def openForAppending(path: String) at async: Int =\n    jsNode "$effekt.capture(callback => open(${path}, \'a\', callback))"\n    llvm !!!MULTILINEMARKER!!!\n      call void @c_fs_open_appending(%Pos ${path}, %Stack %stack)\n      ret void\n    !!!MULTILINEMARKER!!!\n\n  extern def read(file: Int, buffer: ByteArray, offset: Int, size: Int, position: Int) at async: Int =\n    jsNode "$effekt.capture(callback => read(${file}, ${buffer}, ${offset}, ${size}, ${position}, callback))"\n    llvm !!!MULTILINEMARKER!!!\n      call void @c_fs_read(%Int ${file}, %Pos ${buffer}, %Int ${offset}, %Int ${size}, %Int ${position}, %Stack %stack)\n      ret void\n    !!!MULTILINEMARKER!!!\n\n  extern def write(file: Int, buffer: ByteArray, offset: Int, size: Int, position: Int) at async: Int =\n    jsNode "$effekt.capture(callback => write(${file}, ${buffer}, ${offset}, ${size}, ${position}, callback))"\n    llvm !!!MULTILINEMARKER!!!\n      call void @c_fs_write(%Int ${file}, %Pos ${buffer}, %Int ${offset}, %Int ${size}, %Int ${position}, %Stack %stack)\n      ret void\n    !!!MULTILINEMARKER!!!\n\n  extern def close(file: Int) at async: Int =\n    jsNode "$effekt.capture(callback => close(${file}, callback))"\n    llvm !!!MULTILINEMARKER!!!\n      call void @c_fs_close(%Int ${file}, %Stack %stack)\n      ret void\n    !!!MULTILINEMARKER!!!\n\n  extern def mkdir(path: String) at async: Int =\n    jsNode "$effekt.capture(callback => mkdir(${path}, callback))"\n    llvm !!!MULTILINEMARKER!!!\n      call void @c_fs_mkdir(%Pos ${path}, %Stack %stack)\n      ret void\n    !!!MULTILINEMARKER!!!\n\n}\n\nnamespace examples {\n\n  // Example illustrating using abstract files interface\n  // and interpreting it into asynchronous IO\n  def copy(from: String, to: String): Unit / Files = {\n    val contents = do readFile(from)\n    do writeFile(to, contents)\n  }\n\n  def main() = {\n    with on[IOError].panic;\n    with filesystem;\n\n    copy("README.md", "out/test.md")\n  }\n}\n'),tf("common/io/error.effekt",'module io/error\n\n/// Errors defined by libuv that can occur in IO operations.\n///\n/// In addition to the named error codes, we also assign each error a\n/// (positive) integer value that is stable across the different platforms.\n///\n/// For the mapping of IOError and code values, see function fromCode.\n///\n/// While stable, this integer value is supposed to only be used internally.\n/// All user-facing operations should use values of type IOError, instead.\n///\n/// see: https://docs.libuv.org/en/v1.x/errors.html\ntype IOError {\n  E2BIG();\n  EACCES();\n  EADDRINUSE();\n  EADDRNOTAVAIL();\n  EAFNOSUPPORT();\n  EAGAIN();\n  EAI_ADDRFAMILY();\n  EAI_AGAIN();\n  EAI_BADFLAGS();\n  EAI_BADHINTS();\n  EAI_CANCELED();\n  EAI_FAIL();\n  EAI_FAMILY();\n  EAI_MEMORY();\n  EAI_NODATA();\n  EAI_NONAME();\n  EAI_OVERFLOW();\n  EAI_PROTOCOL();\n  EAI_SERVICE();\n  EAI_SOCKTYPE();\n  EALREADY();\n  EBADF();\n  EBUSY();\n  ECANCELED();\n  ECHARSET();\n  ECONNABORTED();\n  ECONNREFUSED();\n  ECONNRESET();\n  EDESTADDRREQ();\n  EEXIST();\n  EFAULT();\n  EFBIG();\n  EHOSTUNREACH();\n  EINTR();\n  EINVAL();\n  EIO();\n  EISCONN();\n  EISDIR();\n  ELOOP();\n  EMFILE();\n  EMSGSIZE();\n  ENAMETOOLONG();\n  ENETDOWN();\n  ENETUNREACH();\n  ENFILE();\n  ENOBUFS();\n  ENODEV();\n  ENOENT();\n  ENOMEM();\n  ENONET();\n  ENOPROTOOPT();\n  ENOSPC();\n  ENOSYS();\n  ENOTCONN();\n  ENOTDIR();\n  ENOTEMPTY();\n  ENOTSOCK();\n  ENOTSUP();\n  EOVERFLOW();\n  EPERM();\n  EPIPE();\n  EPROTO();\n  EPROTONOSUPPORT();\n  EPROTOTYPE();\n  ERANGE();\n  EROFS();\n  ESHUTDOWN();\n  ESPIPE();\n  ESRCH();\n  ETIMEDOUT();\n  ETXTBSY();\n  EXDEV();\n  UNKNOWN();\n  EOF();\n  ENXIO();\n  EMLINK();\n  ENOTTY();\n  EFTYPE();\n  EILSEQ();\n  ESOCKTNOSUPPORT();\n  EUNATCH()\n}\n\n/// Corresponding error message for a libuv error\n///\n/// see: https://docs.libuv.org/en/v1.x/errors.html\ndef message(error: IOError): String = error match {\n  case E2BIG() => "argument list too long"\n  case EACCES() => "permission denied"\n  case EADDRINUSE() => "address already in use"\n  case EADDRNOTAVAIL() => "address not available"\n  case EAFNOSUPPORT() => "address family not supported"\n  case EAGAIN() => "resource temporarily unavailable"\n  case EAI_ADDRFAMILY() => "address family not supported"\n  case EAI_AGAIN() => "temporary failure"\n  case EAI_BADFLAGS() => "bad ai_flags value"\n  case EAI_BADHINTS() => "invalid value for hints"\n  case EAI_CANCELED() => "request canceled"\n  case EAI_FAIL() => "permanent failure"\n  case EAI_FAMILY() => "ai_family not supported"\n  case EAI_MEMORY() => "out of memory"\n  case EAI_NODATA() => "no address"\n  case EAI_NONAME() => "unknown node or service"\n  case EAI_OVERFLOW() => "argument buffer overflow"\n  case EAI_PROTOCOL() => "resolved protocol is unknown"\n  case EAI_SERVICE() => "service not available for socket type"\n  case EAI_SOCKTYPE() => "socket type not supported"\n  case EALREADY() => "connection already in progress"\n  case EBADF() => "bad file descriptor"\n  case EBUSY() => "resource busy or locked"\n  case ECANCELED() => "operation canceled"\n  case ECHARSET() => "invalid Unicode character"\n  case ECONNABORTED() => "software caused connection abort"\n  case ECONNREFUSED() => "connection refused"\n  case ECONNRESET() => "connection reset by peer"\n  case EDESTADDRREQ() => "destination address required"\n  case EEXIST() => "file already exists"\n  case EFAULT() => "bad address in system call argument"\n  case EFBIG() => "file too large"\n  case EHOSTUNREACH() => "host is unreachable"\n  case EINTR() => "interrupted system call"\n  case EINVAL() => "invalid argument"\n  case EIO() => "i/o error"\n  case EISCONN() => "socket is already connected"\n  case EISDIR() => "illegal operation on a directory"\n  case ELOOP() => "too many symbolic links encountered"\n  case EMFILE() => "too many open files"\n  case EMSGSIZE() => "message too long"\n  case ENAMETOOLONG() => "name too long"\n  case ENETDOWN() => "network is down"\n  case ENETUNREACH() => "network is unreachable"\n  case ENFILE() => "file table overflow"\n  case ENOBUFS() => "no buffer space available"\n  case ENODEV() => "no such device"\n  case ENOENT() => "no such file or directory"\n  case ENOMEM() => "not enough memory"\n  case ENONET() => "machine is not on the network"\n  case ENOPROTOOPT() => "protocol not available"\n  case ENOSPC() => "no space left on device"\n  case ENOSYS() => "function not implemented"\n  case ENOTCONN() => "socket is not connected"\n  case ENOTDIR() => "not a directory"\n  case ENOTEMPTY() => "directory not empty"\n  case ENOTSOCK() => "socket operation on non-socket"\n  case ENOTSUP() => "operation not supported on socket"\n  case EOVERFLOW() => "value too large for defined data type"\n  case EPERM() => "operation not permitted"\n  case EPIPE() => "broken pipe"\n  case EPROTO() => "protocol error"\n  case EPROTONOSUPPORT() => "protocol not supported"\n  case EPROTOTYPE() => "protocol wrong type for socket"\n  case ERANGE() => "result too large"\n  case EROFS() => "read-only file system"\n  case ESHUTDOWN() => "cannot send after transport endpoint shutdown"\n  case ESPIPE() => "invalid seek"\n  case ESRCH() => "no such process"\n  case ETIMEDOUT() => "connection timed out"\n  case ETXTBSY() => "text file is busy"\n  case EXDEV() => "cross-device link not permitted"\n  case UNKNOWN() => "unknown error"\n  case EOF() => "end of file"\n  case ENXIO() => "no such device or address"\n  case EMLINK() => "too many links"\n  case ENOTTY() => "inappropriate ioctl for device"\n  case EFTYPE() => "inappropriate file type or format"\n  case EILSEQ() => "illegal byte sequence"\n  case ESOCKTNOSUPPORT() => "socket type not supported"\n  case EUNATCH() => "protocol driver not attached"\n}\n\n/// Corresponding name of a libuv error\n///\n/// see: https://docs.libuv.org/en/v1.x/errors.html\ndef name(error: IOError): String = error match {\n  case E2BIG() => "E2BIG"\n  case EACCES() => "EACCES"\n  case EADDRINUSE() => "EADDRINUSE"\n  case EADDRNOTAVAIL() => "EADDRNOTAVAIL"\n  case EAFNOSUPPORT() => "EAFNOSUPPORT"\n  case EAGAIN() => "EAGAIN"\n  case EAI_ADDRFAMILY() => "EAI_ADDRFAMILY"\n  case EAI_AGAIN() => "EAI_AGAIN"\n  case EAI_BADFLAGS() => "EAI_BADFLAGS"\n  case EAI_BADHINTS() => "EAI_BADHINTS"\n  case EAI_CANCELED() => "EAI_CANCELED"\n  case EAI_FAIL() => "EAI_FAIL"\n  case EAI_FAMILY() => "EAI_FAMILY"\n  case EAI_MEMORY() => "EAI_MEMORY"\n  case EAI_NODATA() => "EAI_NODATA"\n  case EAI_NONAME() => "EAI_NONAME"\n  case EAI_OVERFLOW() => "EAI_OVERFLOW"\n  case EAI_PROTOCOL() => "EAI_PROTOCOL"\n  case EAI_SERVICE() => "EAI_SERVICE"\n  case EAI_SOCKTYPE() => "EAI_SOCKTYPE"\n  case EALREADY() => "EALREADY"\n  case EBADF() => "EBADF"\n  case EBUSY() => "EBUSY"\n  case ECANCELED() => "ECANCELED"\n  case ECHARSET() => "ECHARSET"\n  case ECONNABORTED() => "ECONNABORTED"\n  case ECONNREFUSED() => "ECONNREFUSED"\n  case ECONNRESET() => "ECONNRESET"\n  case EDESTADDRREQ() => "EDESTADDRREQ"\n  case EEXIST() => "EEXIST"\n  case EFAULT() => "EFAULT"\n  case EFBIG() => "EFBIG"\n  case EHOSTUNREACH() => "EHOSTUNREACH"\n  case EINTR() => "EINTR"\n  case EINVAL() => "EINVAL"\n  case EIO() => "EIO"\n  case EISCONN() => "EISCONN"\n  case EISDIR() => "EISDIR"\n  case ELOOP() => "ELOOP"\n  case EMFILE() => "EMFILE"\n  case EMSGSIZE() => "EMSGSIZE"\n  case ENAMETOOLONG() => "ENAMETOOLONG"\n  case ENETDOWN() => "ENETDOWN"\n  case ENETUNREACH() => "ENETUNREACH"\n  case ENFILE() => "ENFILE"\n  case ENOBUFS() => "ENOBUFS"\n  case ENODEV() => "ENODEV"\n  case ENOENT() => "ENOENT"\n  case ENOMEM() => "ENOMEM"\n  case ENONET() => "ENONET"\n  case ENOPROTOOPT() => "ENOPROTOOPT"\n  case ENOSPC() => "ENOSPC"\n  case ENOSYS() => "ENOSYS"\n  case ENOTCONN() => "ENOTCONN"\n  case ENOTDIR() => "ENOTDIR"\n  case ENOTEMPTY() => "ENOTEMPTY"\n  case ENOTSOCK() => "ENOTSOCK"\n  case ENOTSUP() => "ENOTSUP"\n  case EOVERFLOW() => "EOVERFLOW"\n  case EPERM() => "EPERM"\n  case EPIPE() => "EPIPE"\n  case EPROTO() => "EPROTO"\n  case EPROTONOSUPPORT() => "EPROTONOSUPPORT"\n  case EPROTOTYPE() => "EPROTOTYPE"\n  case ERANGE() => "ERANGE"\n  case EROFS() => "EROFS"\n  case ESHUTDOWN() => "ESHUTDOWN"\n  case ESPIPE() => "ESPIPE"\n  case ESRCH() => "ESRCH"\n  case ETIMEDOUT() => "ETIMEDOUT"\n  case ETXTBSY() => "ETXTBSY"\n  case EXDEV() => "EXDEV"\n  case UNKNOWN() => "UNKNOWN"\n  case EOF() => "EOF"\n  case ENXIO() => "ENXIO"\n  case EMLINK() => "EMLINK"\n  case ENOTTY() => "ENOTTY"\n  case EFTYPE() => "EFTYPE"\n  case EILSEQ() => "EILSEQ"\n  case ESOCKTNOSUPPORT() => "ESOCKTNOSUPPORT"\n  case EUNATCH() => "EUNATCH"\n}\n\n/// Translates a integer code value to an IOError.\n///\n/// See documentation of type IOError for further information.\ndef fromNumber(number: Int): IOError = number match {\n  case 1 => EPERM()\n  case 2 => ENOENT()\n  case 3 => ESRCH()\n  case 4 => EINTR()\n  case 5 => EIO()\n  case 6 => ENXIO()\n  case 7 => E2BIG()\n  case 9 => EBADF()\n  case 11 => EAGAIN()\n  case 12 => ENOMEM()\n  case 13 => EACCES()\n  case 14 => EFAULT()\n  case 16 => EBUSY()\n  case 17 => EEXIST()\n  case 18 => EXDEV()\n  case 19 => ENODEV()\n  case 20 => ENOTDIR()\n  case 21 => EISDIR()\n  case 22 => EINVAL()\n  case 23 => ENFILE()\n  case 24 => EMFILE()\n  case 25 => ENOTTY()\n  case 26 => ETXTBSY()\n  case 27 => EFBIG()\n  case 28 => ENOSPC()\n  case 29 => ESPIPE()\n  case 30 => EROFS()\n  case 31 => EMLINK()\n  case 32 => EPIPE()\n  case 34 => ERANGE()\n  case 36 => ENAMETOOLONG()\n  case 40 => ELOOP()\n  case 75 => EOVERFLOW()\n  case 79 => EFTYPE()\n  case 84 => EILSEQ()\n  case 88 => ENOTSOCK()\n  case 89 => EDESTADDRREQ()\n  case 90 => EMSGSIZE()\n  case 91 => EPROTOTYPE()\n  case 92 => ENOPROTOOPT()\n  case 93 => EPROTONOSUPPORT()\n  case 94 => ESOCKTNOSUPPORT()\n  case 95 => ENOTSUP()\n  case 97 => EAFNOSUPPORT()\n  case 98 => EADDRINUSE()\n  case 99 => EADDRNOTAVAIL()\n  case 100 => ENETDOWN()\n  case 101 => ENETUNREACH()\n  case 103 => ECONNABORTED()\n  case 104 => ECONNRESET()\n  case 105 => ENOBUFS()\n  case 106 => EISCONN()\n  case 107 => ENOTCONN()\n  case 110 => ETIMEDOUT()\n  case 111 => ECONNREFUSED()\n  case 113 => EHOSTUNREACH()\n  case 114 => EALREADY()\n  case 125 => ECANCELED()\n\n  case 200 => EAI_ADDRFAMILY()\n  case 201 => EAI_AGAIN()\n  case 202 => EAI_BADFLAGS()\n  case 203 => EAI_BADHINTS()\n  case 204 => EAI_CANCELED()\n  case 205 => EAI_FAIL()\n  case 206 => EAI_FAMILY()\n  case 207 => EAI_MEMORY()\n  case 208 => EAI_NODATA()\n  case 209 => EAI_NONAME()\n  case 210 => EAI_OVERFLOW()\n  case 211 => EAI_PROTOCOL()\n  case 212 => EAI_SERVICE()\n  case 213 => EAI_SOCKTYPE()\n  case 215 => ECHARSET()\n  case 216 => ENONET()\n  case 217 => UNKNOWN()\n  case 218 => EOF()\n  case 219 => EUNATCH()\n  case 220 => ESHUTDOWN()\n\n  case _ => panic("Not a valid error code: " ++ show(number))\n}\n\nnamespace internal {\n\n  extern llvm !!!MULTILINEMARKER!!!\n    declare %Int @c_error_number(%Int)\n  !!!MULTILINEMARKER!!!\n\nextern jsNode !!!MULTILINEMARKER!!!\n    const { getSystemErrorName } = require(\'node:util\');\n\n    /**\n     * Maps the error code to a Effekt-stable (platform independent) numeric value.\n     *\n     * Tries to use most common errno integer values, but introduces fresh values (> 200)\n     * for those without common errno values.\n     *\n     * The mapping from platfrom-specific error codes to Effekt error codes is handled by\n     * getSystemErrorName from \'node:util\', which in turn uses the error code conventions from libuv.\n     * For reference, see the following Deno code which is more readable than the NodeJS implementation:\n     * https://github.com/denoland/deno/blob/8fb073d7b4ea83b57fd1bf9875681347b414bbe6/ext/node/polyfills/internal_binding/uv.ts\n     */\n    function errorNumber(errno) {\n      const mapByName = {\n        EPERM: 1,\n        ENOENT: 2,\n        ESRCH: 3,\n        EINTR: 4,\n        EIO: 5,\n        ENXIO: 6,\n        E2BIG: 7,\n        EBADF: 9,\n        EAGAIN: 11,\n        ENOMEM: 12,\n        EACCES: 13,\n        EFAULT: 14,\n        EBUSY: 16,\n        EEXIST: 17,\n        EXDEV: 18,\n        ENODEV: 19,\n        ENOTDIR: 20,\n        EISDIR: 21,\n        EINVAL: 22,\n        ENFILE: 23,\n        EMFILE: 24,\n        ENOTTY: 25,\n        ETXTBSY: 26,\n        EFBIG: 27,\n        ENOSPC: 28,\n        ESPIPE: 29,\n        EROFS: 30,\n        EMLINK: 31,\n        